// 1. Alle Werte aus HA aufteilen
let parts = msg.payload.split(";");

// Rohe Gesamtwerte
let rawTotalPower = parseFloat(parts[0]) || 0;
let kwh_import = parseFloat(parts[1]) || 0;
let kwh_export = parseFloat(parts[2]) || 0;
let freq = parseFloat(parts[3]) || 50.0;

// === NEU: SMOOTHING (Gleitender Mittelwert) ===
// Holt den letzten geglätteten Wert (oder startet mit dem aktuellen)
let lastSmoothedPower = context.get("smoothed_power") || rawTotalPower;

// Der "Trägheits-Faktor" (Alpha). 
// 0.2 bedeutet: Der neue Wert besteht zu 20% aus dem aktuellen Messwert 
// und zu 80% aus dem alten Wert. Je kleiner die Zahl, desto träger/stabiler.
let alpha = 0.9;

// Die Glättungs-Formel
let fakeTotalPower = (alpha * rawTotalPower) + ((1 - alpha) * lastSmoothedPower);

// Speichert den neuen Wert für den nächsten Durchlauf
context.set("smoothed_power", fakeTotalPower);
// ==============================================


// Spannungen (Alle 3 Phasen separat)
let v1 = parseFloat(parts[4]) || 230.0;
let v2 = parseFloat(parts[5]) || 230.0;
let v3 = parseFloat(parts[6]) || 230.0;

// Phase L1 (Echt)
let p1_w = parseFloat(parts[7]) || 0;
let p1_pf = parseFloat(parts[8]) || 1.0;
let p1_va = (p1_pf !== 0) ? Math.abs(p1_w) / p1_pf : Math.abs(p1_w);

// Phase L2 (Echt)
let p2_w = parseFloat(parts[9]) || 0;
let p2_pf = parseFloat(parts[10]) || 1.0;
let p2_va = (p2_pf !== 0) ? Math.abs(p2_w) / p2_pf : Math.abs(p2_w);

// Phase L3 (KÜNSTLICH BERECHNET auf Basis des GEGLÄTTETEN Wertes)
let p3_w = fakeTotalPower - (p1_w + p2_w);
let p3_pf = 0.99; // Fester Sicherheitswert
let p3_va = Math.abs(p3_w) / p3_pf;

// 3. Globale Speicherung für den Modbus-Emulator
global.set("sdm_total_power", fakeTotalPower);
global.set("sdm_kwh_import", kwh_import);
global.set("sdm_kwh_export", kwh_export);
global.set("sdm_frequenz", freq);

global.set("sdm_v1", v1);
global.set("sdm_v2", v2);
global.set("sdm_v3", v3);

global.set("sdm_l1_w", p1_w);
global.set("sdm_l1_va", p1_va);
global.set("sdm_l1_pf", p1_pf);

global.set("sdm_l2_w", p2_w);
global.set("sdm_l2_va", p2_va);
global.set("sdm_l2_pf", p2_pf);

global.set("sdm_l3_w", p3_w);
global.set("sdm_l3_va", p3_va);
global.set("sdm_l3_pf", p3_pf);

node.status({ fill: "green", shape: "dot", text: "Raw: " + rawTotalPower.toFixed(0) + "W | Smooth: " + fakeTotalPower.toFixed(0) + "W" });
return msg;

function calcReactive(w, va) {
    let val = Math.sqrt(Math.abs((va * va) - (w * w)));
    return isNaN(val) ? 0 : val;
}

let total_power = parseFloat(global.get("sdm_total_power")) || 0;
let kwh_import = parseFloat(global.get("sdm_kwh_import")) || 0;
let kwh_export = parseFloat(global.get("sdm_kwh_export")) || 0;
let freq = parseFloat(global.get("sdm_frequenz")) || 50.0;
let v1 = parseFloat(global.get("sdm_v1")) || 230.0;
let v2 = parseFloat(global.get("sdm_v2")) || 230.0;
let v3 = parseFloat(global.get("sdm_v3")) || 230.0;

let l1_w = parseFloat(global.get("sdm_l1_w")) || 0;
let l1_pf = parseFloat(global.get("sdm_l1_pf")) || 1.0;
let l1_va = (l1_pf !== 0) ? Math.abs(l1_w) / l1_pf : Math.abs(l1_w);
let l1_var = calcReactive(l1_w, l1_va);

let l2_w = parseFloat(global.get("sdm_l2_w")) || 0;
let l2_pf = parseFloat(global.get("sdm_l2_pf")) || 1.0;
let l2_va = (l2_pf !== 0) ? Math.abs(l2_w) / l2_pf : Math.abs(l2_w);
let l2_var = calcReactive(l2_w, l2_va);

let l3_w = parseFloat(global.get("sdm_l3_w")) || 0; 
let l3_pf = 0.99; 
let l3_va = Math.abs(l3_w) / l3_pf;
let l3_var = calcReactive(l3_w, l3_va);

let l1_a = Math.abs(l1_va / v1);
let l2_a = Math.abs(l2_va / v2);
let l3_a = Math.abs(l3_va / v3);

let total_va = l1_va + l2_va + l3_va;
let total_var = l1_var + l2_var + l3_var;
let total_pf = (total_va > 0) ? Math.abs(total_power / total_va) : 1.0;

let req = msg.payload;
if (!Buffer.isBuffer(req) || req.length < 8) return null;

let slaveId = req[0];

// === DER FIX: NUR NOCH EASTRON (ID 2) AKZEPTIEREN ===
// Wenn der Growatt nach Chint (ID 1) sucht, stellen wir uns tot.
if (slaveId !== 2) {
    return null; 
}

let fc = req[1];
let startReg = req.readUInt16BE(2); 
let regCount = req.readUInt16BE(4);

let res;
if (fc === 3) { 
    res = Buffer.alloc(3 + (regCount * 2) + 2);
    res[0] = slaveId; res[1] = fc; res[2] = regCount * 2;
    if (startReg === 16384) {
        let name = "SDM630";
        for (let i = 0; i < name.length; i++) { res[3 + i] = name.charCodeAt(i); }
    }
} else if (fc === 4) { 
    res = Buffer.alloc(3 + (regCount * 2) + 2);
    res[0] = slaveId; res[1] = fc; res[2] = regCount * 2;

    function writeFloat(buf, addr, val, start, count) {
        if (addr >= start && addr < start + count) {
            let off = 3 + ((addr - start) * 2);
            if(off + 4 <= buf.length - 2) {
                buf.writeFloatBE(val, off);
            }
        }
    }

    writeFloat(res, 0, v1, startReg, regCount);
    writeFloat(res, 2, v2, startReg, regCount);
    writeFloat(res, 4, v3, startReg, regCount);
    writeFloat(res, 6, l1_a, startReg, regCount);
    writeFloat(res, 8, l2_a, startReg, regCount);
    writeFloat(res, 10, l3_a, startReg, regCount);
    writeFloat(res, 12, l1_w, startReg, regCount);
    writeFloat(res, 14, l2_w, startReg, regCount);
    writeFloat(res, 16, l3_w, startReg, regCount);
    writeFloat(res, 18, l1_va, startReg, regCount);
    writeFloat(res, 20, l2_va, startReg, regCount);
    writeFloat(res, 22, l3_va, startReg, regCount);
    writeFloat(res, 24, l1_var, startReg, regCount);
    writeFloat(res, 26, l2_var, startReg, regCount);
    writeFloat(res, 28, l3_var, startReg, regCount);
    writeFloat(res, 30, l1_pf, startReg, regCount);
    writeFloat(res, 32, l2_pf, startReg, regCount);
    writeFloat(res, 34, l3_pf, startReg, regCount);

    writeFloat(res, 52, total_power, startReg, regCount);
    writeFloat(res, 56, total_va, startReg, regCount);
    writeFloat(res, 60, total_var, startReg, regCount);
    writeFloat(res, 62, total_pf, startReg, regCount);
    writeFloat(res, 70, freq, startReg, regCount);
    writeFloat(res, 72, kwh_import, startReg, regCount);
    writeFloat(res, 74, kwh_export, startReg, regCount);
    writeFloat(res, 342, kwh_import, startReg, regCount);
    writeFloat(res, 344, kwh_export, startReg, regCount);
}

if (res) {
    let crc = 0xFFFF;
    for (let i = 0; i < res.length - 2; i++) {
        crc ^= res[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 1) { crc >>= 1; crc ^= 0xA001; } else { crc >>= 1; }
        }
    }
    res.writeUInt16LE(crc, res.length - 2);
    msg.payload = res;
    return msg;
}
return null;
